#!/usr/bin/python

import sys
import time


routes = [
'announce  route 11.10.0.0/24 next-hop 7.1.1.10',
'announce  route 11.20.0.0/24 next-hop 7.1.1.10',
]

time.sleep(5)

#Iterate through routes
